Here's how to structure the tests using modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, HttpClient client) CreateFetcher(HttpMessageHandler handler)
    {
        var client = new HttpClient(handler);
        return (new DataFetcher(client), client);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        using var handler = new MockHandler(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.OK,
            Content = new StringContent("hello world"),
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        using var handler = new MockHandler(new HttpResponseMessage
        {
            StatusCode = System.Net.HttpStatusCode.InternalServerError,
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceledException()
    {
        // Arrange
        using var handler = new MockHandler(delay: TimeSpan.FromSeconds(30));
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_SlowResponse_CancelledByTimeout()
    {
        // Arrange
        using var handler = new MockHandler(delay: TimeSpan.FromSeconds(30));
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));

        // Act & Assert — token fires after 100ms, well before the 30s delay
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    /// <summary>Minimal HttpMessageHandler that returns a canned response.</summary>
    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        private readonly TimeSpan _delay;

        public MockHandler(HttpResponseMessage? response = null, TimeSpan delay = default)
        {
            _response = response ?? new HttpResponseMessage(System.Net.HttpStatusCode.OK);
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken);
            }

            return _response;
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext.CancellationToken` | Cooperative timeout — if `[Timeout]` fires, your async calls stop cleanly |
| `Assert.ThrowsExactlyAsync<T>` | Verifies the exact exception type, replaces `[ExpectedException]` |
| `[Timeout(5000)]` on every async test | Prevents hangs; pairs with `CancellationToken` |
| `sealed` class + `MockHandler` | Avoids pulling in a mocking library for a simple `HttpClient` scenario |
| Constructor-injected `TestContext` | Enables `readonly` field, satisfies nullability |

The `SlowResponse_CancelledByTimeout` test is the critical one — it proves your `FetchAsync` properly propagates the `CancellationToken` down to `HttpClient.GetAsync`, so callers can enforce deadlines.
